-- ═══════════════════════════════════════════════════════
-- MATTHEW CHAPTER 5 — The Kingdom Citizen's Radical Righteousness and Ethical Demands
-- 48 verses · Original text · Word studies · Cross-refs
-- ═══════════════════════════════════════════════════════

-- Step 1: Insert chapter metadata
INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 5,
  'Matthew Chapter 5 inaugurates the Sermon on the Mount, presenting Jesus'' radical reinterpretation of the Mosaic Law and the nature of true righteousness. It begins with the Beatitudes, outlining the character traits of citizens in the Kingdom of Heaven, followed by their role as ''salt and light'' in the world. Jesus then clarifies that he came not to abolish but to fulfill the Law and the Prophets, deepening their ethical demands from external actions to internal thoughts and intentions. He provides six antitheses, contrasting traditional interpretations (''You have heard that it was said...'') with his authoritative teaching (''But I say to you...''), covering anger, lust, divorce, oaths, retaliation, and love for enemies. The chapter culminates in a call to perfection, mirroring God''s own character, thereby establishing a foundational ethical framework for Christian discipleship that transcends mere legalism and calls for profound internal transformation.',
  'The Kingdom Citizen''s Radical Righteousness and Ethical Demands',
  'δικαιοσύνη (dikaiosynē)',
  'From ''δίκαιος (dikaios)'' meaning ''just, righteous''. In a biblical context, it refers to conformity to God''s standard, both in character and action. It encompasses ethical uprightness, justice, and the state of being right with God. Jesus redefines it as an internal disposition exceeding mere external legalism, essential for kingdom entry and reflecting God''s character.',
  '["Section 1 (vv.1-12): The Character of Kingdom Citizens (The Beatitudes)","Section 2 (vv.13-16): The Influence of Kingdom Citizens (Salt and Light)","Section 3 (vv.17-20): Jesus and the Law: Fulfillment, Not Abolition","Section 4 (vv.21-26): Righteousness and Anger: Beyond Murder","Section 5 (vv.27-32): Righteousness and Lust: Beyond Adultery","Section 6 (vv.33-37): Righteousness and Oaths: Beyond False Swearing","Section 7 (vv.38-42): Righteousness and Retaliation: Beyond ''Eye for an Eye''","Section 8 (vv.43-48): Righteousness and Love: Beyond Loving Neighbors Only"]'
FROM books b WHERE b.name = 'Matthew';

-- Step 2: Insert all 48 verses
INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1,
   'And seeing the multitudes, he went up into a mountain: and when he was set, his disciples came unto him:',
   'Ἰδὼν δὲ τοὺς ὄχλους, ἀνέβη εἰς τὸ ὄρος· καὶ καθίσαντος αὐτοῦ προσῆλθον αὐτῷ οἱ μαθηταὶ αὐτοῦ·',
   'Idōn de tous ochlous, anebē eis to oros; kai kathisantos autou prosēlthon autō hoi mathētai autou:',
   'Jesus'' ascent ''into a mountain'' (τὸ ὄρος) recalls Moses receiving the Law on Mount Sinai, subtly positioning Jesus as a new Moses, delivering a new covenant teaching. The setting is intimate, with ''his disciples'' (οἱ μαθηταὶ αὐτοῦ) coming to him, though the ''multitudes'' (τοὺς ὄχλους) are still in view, suggesting the teaching is for both inner circle and broader audience. This sets the stage for the Sermon on the Mount, a foundational discourse on kingdom ethics (Matt 5:2).',
   NULL),
  (2,
   'And he opened his mouth, and taught them, saying,',
   'καὶ ἀνοίξας τὸ στόμα αὐτοῦ ἐδίδασκεν αὐτοὺς λέγων·',
   'kai anoixas to stoma autou edidasken autous legōn:',
   'The phrase ''he opened his mouth'' (ἀνοίξας τὸ στόμα αὐτοῦ) is a Hebraism indicating a solemn and significant discourse is about to begin, emphasizing the importance of the words that follow. Jesus ''taught them'' (ἐδίδασκεν αὐτοὺς), signifying his authority as a teacher (rabbi), distinct from the scribes. This verse transitions directly into the Beatitudes, the core of his ethical instruction (Matt 7:28-29).',
   NULL),
  (3,
   'Blessed are the poor in spirit: for theirs is the kingdom of heaven.',
   'Μακάριοι οἱ πτωχοὶ τῷ πνεύματι, ὅτι αὐτῶν ἐστιν ἡ βασιλεία τῶν οὐρανῶν.',
   'Makarioi hoi ptōchoi tō pneumati, hoti autōn estin hē basileia tōn ouranōn.',
   'The first Beatitude declares ''blessed'' (μακάριοι) those who are ''poor in spirit'' (οἱ πτωχοὶ τῷ πνεύματι). This refers not to material poverty, but to a spiritual humility and dependence on God, acknowledging one''s utter spiritual bankruptcy and need for divine grace. Such a disposition is foundational for receiving ''the kingdom of heaven'' (ἡ βασιλεία τῶν οὐρανῶν), which is both a present reality and a future hope. This contrasts sharply with self-righteousness (Luke 18:9-14).',
   'This verse introduces the core concept of spiritual humility as the gateway to God''s kingdom. It teaches that true blessedness comes not from self-sufficiency or worldly status, but from recognizing one''s spiritual need and dependence on God, a foundational principle for Christian discipleship and salvation.'),
  (4,
   'Blessed are they that mourn: for they shall be comforted.',
   'Μακάριοι οἱ πενθοῦντες, ὅτι αὐτοὶ παρακληθήσονται.',
   'Makarioi hoi penthountes, hoti autoi paraklēthēsontai.',
   'The ''mourners'' (οἱ πενθοῦντες) are those who grieve over sin—their own and the world''s brokenness—and perhaps also those who suffer affliction for righteousness'' sake. This mourning is not despair but a godly sorrow that leads to repentance (2 Cor 7:10). Their blessedness lies in the promise that ''they shall be comforted'' (παρακληθήσονται), a comfort that comes from God''s presence, forgiveness, and the hope of ultimate restoration.',
   'This Beatitude highlights the blessedness of godly sorrow, which recognizes the gravity of sin and the brokenness of the world. It promises divine comfort and restoration to those who genuinely mourn, pointing to the redemptive work of Christ and the ultimate hope of a new heaven and new earth.'),
  (5,
   'Blessed are the meek: for they shall inherit the earth.',
   'Μακάριοι οἱ πραεῖς, ὅτι αὐτοὶ κληρονομήσουσιν τὴν γῆν.',
   'Makarioi hoi praeis, hoti autoi klēronomēsousin tēn gēn.',
   'The ''meek'' (οἱ πραεῖς) are not weak, but gentle, humble, and submissive to God''s will, exercising strength under control. This virtue is exemplified by Moses (Num 12:3) and Jesus himself (Matt 11:29). The promise to ''inherit the earth'' (κληρονομήσουσιν τὴν γῆν) echoes Psalm 37:11, referring to a spiritual inheritance in God''s kingdom, which includes both present blessings and future dominion in the new creation (Rev 5:10).',
   'Meekness, as taught here, is a Christ-like virtue of gentle strength and submission to God. It promises an inheritance of the earth, signifying not worldly power but participation in God''s redemptive plan and a share in the renewed creation, demonstrating that true authority comes through humility.'),
  (6,
   'Blessed are they which do hunger and thirst after righteousness: for they shall be filled.',
   'Μακάριοι οἱ πεινῶντες καὶ διψῶντες τὴν δικαιοσύνην, ὅτι αὐτοὶ χορτασθήσονται.',
   'Makarioi hoi peinōntes kai dipsōntes tēn dikaiosynēn, hoti autoi chortasthēsontai.',
   'This Beatitude describes an intense spiritual longing: ''hunger and thirst after righteousness'' (πεινῶντες καὶ διψῶντες τὴν δικαιοσύνην). This is not merely a desire for justice, but for personal conformity to God''s holy character and will. It implies a deep dissatisfaction with one''s own spiritual state and a fervent pursuit of God''s ways. The promise is that ''they shall be filled'' (χορτασθήσονται), indicating complete satisfaction and spiritual fulfillment through Christ (John 6:35).',
   'This verse underscores the blessedness of a profound spiritual yearning for God''s righteousness. It teaches that those who earnestly seek to live in accordance with God''s holy standards will find complete satisfaction and fulfillment in Him, highlighting the transformative power of divine grace.'),
  (7,
   'Blessed are the merciful: for they shall obtain mercy.',
   'Μακάριοι οἱ ἐλεήμονες, ὅτι αὐτοὶ ἐλεηθήσονται.',
   'Makarioi hoi eleēmones, hoti autoi eleēthēsontai.',
   'The ''merciful'' (οἱ ἐλεήμονες) are those who show compassion and active kindness to others, especially those in need or distress. This mercy is not just an emotion but an action, reflecting God''s own character (Luke 6:36). The reciprocal promise, ''they shall obtain mercy'' (ἐλεηθήσονται), emphasizes that God''s grace and forgiveness are extended to those who extend it to others, a principle reiterated in the Lord''s Prayer (Matt 6:14-15).',
   'This Beatitude establishes mercy as a core attribute of kingdom citizens, reflecting God''s character. It teaches a principle of divine reciprocity: those who show active compassion and kindness to others will themselves receive God''s mercy, underscoring the importance of practical love in Christian living.'),
  (8,
   'Blessed are the pure in heart: for they shall see God.',
   'Μακάριοι οἱ καθαροὶ τῇ καρδίᾳ, ὅτι αὐτοὶ τὸν Θεὸν ὄψονται.',
   'Makarioi hoi katharoi tē kardia, hoti autoi ton Theon opsontai.',
   'To be ''pure in heart'' (οἱ καθαροὶ τῇ καρδίᾳ) means to have an undivided devotion to God, free from hypocrisy, duplicity, and hidden sin. It refers to inner integrity and sincerity of motive, rather than mere outward conformity. The profound promise, ''they shall see God'' (τὸν Θεὸν ὄψονται), speaks of an intimate, unhindered fellowship with God, both in this life through spiritual discernment and ultimately in the eschatological vision of His presence (1 John 3:2; Rev 22:4).',
   'Purity of heart is presented as essential for true spiritual vision and intimacy with God. This Beatitude teaches that genuine, internal integrity and undivided devotion to God enable believers to ''see'' and experience Him, both spiritually in the present and ultimately in His glorious presence.'),
  (9,
   'Blessed are the peacemakers: for they shall be called the children of God.',
   'Μακάριοι οἱ εἰρηνοποιοί, ὅτι αὐτοὶ υἱοὶ Θεοῦ κληθήσονται.',
   'Makarioi hoi eirēnopoiē, hoti autoi huioi Theou klēthēsontai.',
   'The ''peacemakers'' (οἱ εἰρηνοποιοί) are not merely passive lovers of peace, but active agents who work to reconcile conflicting parties and promote harmony. They embody God''s own work of reconciliation through Christ (2 Cor 5:18-20). Their blessedness is that ''they shall be called the children of God'' (υἱοὶ Θεοῦ κληθήσονται), reflecting their participation in God''s character and mission to bring peace to a broken world (Rom 12:18).',
   'This Beatitude elevates active peacemaking to a divine characteristic, identifying those who work for reconciliation as ''children of God.'' It underscores the Christian''s calling to embody God''s redemptive work in a fractured world, reflecting His nature as the ultimate Peacemaker.'),
  (10,
   'Blessed are they which are persecuted for righteousness’ sake: for theirs is the kingdom of heaven.',
   'Μακάριοι οἱ δεδιωγμένοι ἕνεκεν δικαιοσύνης, ὅτι αὐτῶν ἐστιν ἡ βασιλεία τῶν οὐρανῶν.',
   'Makarioi hoi dediōgmenoi heneken dikaiosynēs, hoti autōn estin hē basileia tōn ouranōn.',
   'This Beatitude addresses the reality of suffering for faith: ''persecuted for righteousness'' sake'' (δεδιωγμένοι ἕνεκεν δικαιοσύνης). This persecution is a consequence of living out the kingdom ethics described in the preceding Beatitudes. It confirms that true discipleship often involves opposition from the world. The reward is the same as the first Beatitude: ''theirs is the kingdom of heaven'' (αὐτῶν ἐστιν ἡ βασιλεία τῶν οὐρανῶν), emphasizing that suffering for Christ is a mark of genuine belonging to His kingdom (2 Tim 3:12).',
   'This Beatitude affirms that suffering for righteousness is a mark of true discipleship and a pathway to the Kingdom of Heaven. It teaches that persecution, when endured for Christ''s sake, does not diminish but rather confirms one''s blessed status and inheritance in God''s eternal reign.'),
  (11,
   'Blessed are ye, when men shall revile you, and persecute you, and shall say all manner of evil against you falsely, for my sake.',
   'Μακάριοί ἐστε ὅταν ὀνειδίσωσιν ὑμᾶς καὶ διώξωσιν καὶ εἴπωσιν πᾶν πονηρὸν καθ’ ὑμῶν ψευδόμενοι ἕνεκεν ἐμοῦ.',
   'Makarioi este hotan oneidisōsin humas kai diōxōsin kai eipōsin pan ponēron kath'' humōn pseudomenoi heneken emou.',
   'This verse particularizes the previous Beatitude, shifting from ''they'' to ''you,'' making the application direct to the disciples. It specifies various forms of persecution: ''revile you, and persecute you, and shall say all manner of evil against you falsely'' (ὀνειδίσωσιν ὑμᾶς καὶ διώξωσιν καὶ εἴπωσιν πᾶν πονηρὸν καθ’ ὑμῶν ψευδόμενοι). The crucial qualifier is ''for my sake'' (ἕνεκεν ἐμοῦ), indicating that suffering for Christ is the true measure of blessedness, aligning believers with His own experience of rejection (John 15:20).',
   'This verse clarifies that blessedness in persecution is specifically tied to suffering ''for my sake,'' meaning for Christ and His gospel. It teaches that enduring false accusations and hostility as a result of one''s allegiance to Jesus is a sign of genuine discipleship and a pathway to divine reward.'),
  (12,
   'Rejoice, and be exceeding glad: for great is your reward in heaven: for so persecuted they the prophets which were before you.',
   'χαίρετε καὶ ἀγαλλιᾶσθε, ὅτι ὁ μισθὸς ὑμῶν πολὺς ἐν τοῖς οὐρανοῖς· οὕτως γὰρ ἐδίωξαν τοὺς προφήτας τοὺς πρὸ ὑμῶν.',
   'chairete kai agalliasthe, hoti ho misthos humōn polys en tois ouranois; houtōs gar ediōxan tous prophētas tous pro humōn.',
   'Instead of despair, Jesus calls for ''rejoice, and be exceeding glad'' (χαίρετε καὶ ἀγαλλιᾶσθε) in the face of persecution. The reason is the ''great reward in heaven'' (ὁ μισθὸς ὑμῶν πολὺς ἐν τοῖς οὐρανοῖς), emphasizing an eternal perspective. Furthermore, disciples are placed in the esteemed company of ''the prophets which were before you'' (τοὺς προφήτας τοὺς πρὸ ὑμῶν), who also suffered for their faithfulness, providing a historical and theological precedent for Christian suffering (Acts 7:52).',
   'This verse provides a powerful motivation for enduring persecution: a ''great reward in heaven'' and solidarity with the persecuted prophets of old. It teaches believers to find joy in suffering for Christ, knowing their faithfulness will be eternally honored and that they walk in the footsteps of God''s faithful witnesses.'),
  (13,
   'Ye are the salt of the earth: but if the salt have lost his savour, wherewith shall it be salted? it is thenceforth good for nothing, but to be cast out, and to be trodden under foot of men.',
   'Ὑμεῖς ἐστε τὸ ἅλας τῆς γῆς· ἐὰν δὲ τὸ ἅλας μωρανθῇ, ἐν τίνι ἁλισθήσεται; εἰς οὐδὲν ἰσχύει ἔτι εἰ μὴ βληθὲν ἔξω καταπατεῖσθαι ὑπὸ τῶν ἀνθρώπων.',
   'Humeis este to halas tēs gēs; ean de to halas mōranthē, en tini halisthēsetai? eis ouden ischuei eti ei mē blēthen exō katapateisthai hypo tōn anthrōpōn.',
   'Jesus declares his disciples ''the salt of the earth'' (τὸ ἅλας τῆς γῆς). Salt in the ancient world had two primary functions: preservation and flavor. Disciples are called to preserve society from moral decay and to add spiritual ''flavor'' to the world. However, if ''the salt have lost his savour'' (μωρανθῇ), meaning it becomes tasteless or ineffective, it is ''good for nothing'' (εἰς οὐδὲν ἰσχύει ἔτι), emphasizing the critical importance of maintaining spiritual distinctiveness and influence (Col 4:6).',
   'This metaphor highlights the Christian''s vital role in the world: to preserve moral integrity and enhance spiritual truth. It warns against spiritual compromise, emphasizing that a loss of distinctiveness renders believers ineffective and unable to fulfill their God-given purpose, with serious implications for their witness.'),
  (14,
   'Ye are the light of the world. A city that is set on an hill cannot be hid.',
   'Ὑμεῖς ἐστε τὸ φῶς τοῦ κόσμου. οὐ δύναται πόλις κρυβῆναι ἐπάνω ὄρους κειμένη·',
   'Humeis este to phōs tou kosmou. ou dynatai polis krybēnai epanō orous keimenē:',
   'Following the ''salt'' metaphor, Jesus calls his disciples ''the light of the world'' (τὸ φῶς τοῦ κόσμου). Light illuminates, guides, and exposes. Believers are to reflect Christ, the true Light (John 8:12), into a world darkened by sin. The image of ''A city that is set on an hill cannot be hid'' (πόλις κρυβῆναι ἐπάνω ὄρους κειμένη) emphasizes the public and visible nature of Christian witness. Disciples are meant to be seen and to shine brightly (Phil 2:15).',
   'This metaphor defines the Christian''s public identity and mission: to illuminate the world with God''s truth and righteousness. It teaches that believers are called to be visible examples of Christ''s light, demonstrating God''s presence and character in a way that cannot be concealed.'),
  (15,
   'Neither do men light a candle, and put it under a bushel, but on a candlestick; and it giveth light unto all that are in the house.',
   'οὐδὲ καίουσιν λύχνον καὶ τιθέασιν αὐτὸν ὑπὸ τὸν μόδιον ἀλλ’ ἐπὶ τὴν λυχνίαν, καὶ λάμπει πᾶσιν τοῖς ἐν τῇ οἰκίᾳ.',
   'oude kaiousin lychnon kai titheasin auton hypo ton modion all'' epi tēn lychnian, kai lampeipasins tois en tē oikia.',
   'This verse extends the ''light'' metaphor with a practical illustration. No one lights a ''candle'' (λύχνον) only to hide it ''under a bushel'' (ὑπὸ τὸν μόδιον, a grain-measuring basket), but rather places it ''on a candlestick'' (ἐπὶ τὴν λυχνίαν) so it can illuminate ''all that are in the house'' (πᾶσιν τοῖς ἐν τῇ οἰκίᾳ). This reinforces the idea that Christian witness is meant to be visible and impactful, not concealed or privatized (Mark 4:21; Luke 8:16).',
   'This illustration emphasizes the imperative for believers to openly display their faith and good works. It teaches that Christian influence is meant to be public and pervasive, not hidden, so that it can effectively illuminate and benefit all within its sphere of reach.'),
  (16,
   'Let your light so shine before men, that they may see your good works, and glorify your Father which is in heaven.',
   'Οὕτως λαμψάτω τὸ φῶς ὑμῶν ἔμπροσθεν τῶν ἀνθρώπων, ὅπως ἴδωσιν ὑμῶν τὰ καλὰ ἔργα καὶ δοξάσωσιν τὸν Πατέρα ὑμῶν τὸν ἐν τοῖς οὐρανοῖς.',
   'Houtōs lampsatō to phōs humōn emprosthen tōn anthrōpōn, hopōs idōsin humōn ta kala erga kai doxasōsin ton Paterahumon ton en tois ouranois.',
   'The purpose of shining ''your light'' (τὸ φῶς ὑμῶν) ''before men'' (ἔμπροσθεν τῶν ἀνθρώπων) is not self-glorification, but that others ''may see your good works'' (ἴδωσιν ὑμῶν τὰ καλὰ ἔργα) and, crucially, ''glorify your Father which is in heaven'' (δοξάσωσιν τὸν Πατέρα ὑμῶν τὸν ἐν τοῖς οὐρανοῖς). This highlights the evangelistic and doxological aim of Christian living: our righteous actions should point others to God, not to ourselves (1 Pet 2:12).',
   'This verse articulates the ultimate purpose of Christian witness: that believers'' ''good works'' should lead others to glorify God. It teaches that our transformed lives are meant to be a testimony to God''s power and goodness, drawing people to acknowledge and worship our Heavenly Father.'),
  (17,
   'Think not that I am come to destroy the law, or the prophets: I am not come to destroy, but to fulfil.',
   'Μὴ νομίσητε ὅτι ἦλθον καταλῦσαι τὸν νόμον ἢ τοὺς προφήτας· οὐκ ἦλθον καταλῦσαι ἀλλὰ πληρῶσαι.',
   'Mē nomisēte hoti ēlthen katalysai ton nomon ē tous prophētas; ouk ēlthen katalysai alla plērōsai.',
   'Jesus directly addresses a potential misunderstanding: ''Think not that I am come to destroy the law, or the prophets'' (Μὴ νομίσητε ὅτι ἦλθον καταλῦσαι τὸν νόμον ἢ τοὺς προφήτας). ''The Law and the Prophets'' refers to the entire Old Testament revelation. Jesus emphatically states, ''I am not come to destroy, but to fulfil'' (οὐκ ἦλθον καταλῦσαι ἀλλὰ πληρῶσαι). ''To fulfil'' (πληρῶσαι) means to bring to its intended purpose, to complete, to embody, and to perfectly obey, revealing its full spiritual meaning (Rom 10:4).',
   'This pivotal statement clarifies Jesus'' relationship to the Old Testament. He did not abolish the Law but fulfilled it, both by perfectly obeying its demands and by revealing its ultimate spiritual intent. This teaches that Christ is the culmination of God''s redemptive plan, bringing the Old Covenant to its intended purpose.'),
  (18,
   'For verily I say unto you, Till heaven and earth pass, one jot or one tittle shall in no wise pass from the law, till all be fulfilled.',
   'Ἀμὴν γὰρ λέγω ὑμῖν, ἕως ἂν παρέλθῃ ὁ οὐρανὸς καὶ ἡ γῆ, ἰῶτα ἓν ἢ μία κεραία οὐ μὴ παρέλθῃ ἀπὸ τοῦ νόμου, ἕως ἂν πάντα γένηται.',
   'Amēn gar legō humin, heōs an parelthē ho ouranos kai hē gē, iōta hen ē mia keraia ou mē parelthē apo tou nomou, heōs an panta genētai.',
   'Jesus uses a strong affirmation, ''Verily I say unto you'' (Ἀμὴν γὰρ λέγω ὑμῖν), to underscore the enduring authority and permanence of the Law. He states that ''one jot or one tittle'' (ἰῶτα ἓν ἢ μία κεραία)—the smallest letter (iota) or a tiny stroke distinguishing similar letters in Hebrew—''shall in no wise pass from the law'' (οὐ μὴ παρέλθῃ ἀπὸ τοῦ νόμου) until ''all be fulfilled'' (πάντα γένηται). This emphasizes the divine origin and complete fulfillment of every detail of God''s word, ultimately in Christ (Luke 16:17).',
   'This verse powerfully asserts the absolute and enduring authority of God''s Word. It teaches that every detail of the Law and Prophets is divinely inspired and will be perfectly fulfilled, primarily through Christ''s life, death, and resurrection, demonstrating God''s faithfulness to His covenant promises.'),
  (19,
   'Whosoever therefore shall break one of these least commandments, and shall teach men so, he shall be called the least in the kingdom of heaven: but whosoever shall do and teach them, the same shall be called great in the kingdom of heaven.',
   'Ὃς ἐὰν οὖν λύσῃ μίαν τῶν ἐντολῶν τούτων τῶν ἐλαχίστων καὶ διδάξῃ οὕτως τοὺς ἀνθρώπους, ἐλάχιστος κληθήσεται ἐν τῇ βασιλείᾳ τῶν οὐρανῶν· ὃς δ’ ἂν ποιήσῃ καὶ διδάξῃ, οὗτος μέγας κληθήσεται ἐν τῇ βασιλείᾳ τῶν οὐρανῶν.',
   'Hos ean oun lysē mian tōn entolōn toutōn tōn elachistōn kai didaxē houtōs tous anthrōpous, elachistos klēthēsetai en tē basileia tōn ouranōn; hos d'' an poiēsē kai didaxē, houtos megas klēthēsetai en tē basileia tōn ouranōn.',
   'Jesus warns against ''break[ing] one of these least commandments'' (λύσῃ μίαν τῶν ἐντολῶν τούτων τῶν ἐλαχίστων) and teaching others to do so, resulting in being ''called the least in the kingdom of heaven'' (ἐλάχιστος κληθήσεται ἐν τῇ βασιλείᾳ τῶν οὐρανῶν). Conversely, ''whosoever shall do and teach them'' (ὃς δ’ ἂν ποιήσῃ καὶ διδάξῃ) will be ''called great'' (μέγας κληθήσεται). This highlights the importance of both obedience (doing) and faithful instruction (teaching) concerning God''s commands, emphasizing the ethical demands of kingdom citizenship (James 2:10).',
   'This verse underscores the importance of both obedience and faithful teaching of God''s commands for kingdom standing. It teaches that true greatness in God''s kingdom is measured by one''s commitment to upholding and living out even the ''least'' of God''s precepts, demonstrating the integral link between faith and works.'),
  (20,
   'For I say unto you, That except your righteousness shall exceed the righteousness of the scribes and Pharisees, ye shall in no case enter into the kingdom of heaven.',
   'Λέγω γὰρ ὑμῖν ὅτι ἐὰν μὴ περισσεύσῃ ὑμῶν ἡ δικαιοσύνη πλεῖον τῶν γραμματέων καὶ Φαρισαίων, οὐ μὴ εἰσέλθητε εἰς τὴν βασιλείαν τῶν οὐρανῶν.',
   'Legō gar humin hoti ean mē perisseusē humōn hē dikaiosynē pleion tōn grammateōn kai Pharisaiōn, ou mē eiselthēte eis tēn basileia tōn ouranōn.',
   'Jesus makes a startling declaration: ''except your righteousness shall exceed the righteousness of the scribes and Pharisees, ye shall in no case enter into the kingdom of heaven'' (ἐὰν μὴ περισσεύσῃ ὑμῶν ἡ δικαιοσύνη πλεῖον τῶν γραμματέων καὶ Φαρισαίων, οὐ μὴ εἰσέλθητε εἰς τὴν βασιλείαν τῶν οὐρανῶν). The scribes and Pharisees were known for their meticulous adherence to the Law. Jesus is not advocating for more external legalism, but for a deeper, internal righteousness of the heart, which is the true fulfillment of the Law (Rom 9:30-32).',
   'This verse sets a radical standard for entry into the Kingdom of Heaven, demanding a righteousness that surpasses the external legalism of the Pharisees. It teaches that true righteousness is not merely outward conformity but an internal transformation of the heart, achievable only through Christ and His indwelling Spirit, which is foundational for salvation.'),
  (21,
   'Ye have heard that it was said by them of old time, Thou shalt not kill; and whosoever shall kill shall be in danger of the judgment:',
   'Ἠκούσατε ὅτι ἐρρέθη τοῖς ἀρχαίοις, Οὐ φονεύσεις· ὃς δ’ ἂν φονεύσῃ, ἔνοχος ἔσται τῇ κρίσει.',
   'Ēkousate hoti errhethē tois archaiois, Ou phoneuseis; hos d'' an phoneusē, enochos estai tē krisei.',
   'This is the first of six ''antitheses'' where Jesus contrasts traditional interpretations of the Law with his own deeper understanding. He begins with the sixth commandment, ''Thou shalt not kill'' (Οὐ φονεύσεις) (Exod 20:13; Deut 5:17). The traditional understanding focused on the physical act of murder, with the consequence being ''in danger of the judgment'' (ἔνοχος ἔσται τῇ κρίσει), referring to local courts. Jesus is about to reveal the internal dimension of this command.',
   NULL),
  (22,
   'But I say unto you, That whosoever is angry with his brother without a cause shall be in danger of the judgment: and whosoever shall say to his brother, Raca, shall be in danger of the council: but whosoever shall say, Thou fool, shall be in danger of hell fire.',
   'Ἐγὼ δὲ λέγω ὑμῖν ὅτι πᾶς ὁ ὀργιζόμενος τῷ ἀδελφῷ αὐτοῦ εἰκῇ ἔνοχος ἔσται τῇ κρίσει· ὃς δ’ ἂν εἴπῃ τῷ ἀδελφῷ αὐτοῦ, Ῥακά, ἔνοχος ἔσται τῷ συνεδρίῳ· ὃς δ’ ἂν εἴπῃ, Μωρέ, ἔνοχος ἔσται εἰς τὴν γέενναν τοῦ πυρός.',
   'Egō de legō humin hoti pas ho orgizomenos tō adelphō autou eikē enochos estai tē krisei; hos d'' an eipē tō adelphō autou, Rhaka, enochos estai tō synedriō; hos d'' an eipē, Mōre, enochos estai eis tēn geennan tou pyros.',
   'Jesus radically redefines murder to include internal anger. ''Whosoever is angry with his brother without a cause'' (πᾶς ὁ ὀργιζόμενος τῷ ἀδελφῷ αὐτοῦ εἰκῇ) is ''in danger of the judgment'' (ἔνοχος ἔσται τῇ κρίσει). Using contemptuous terms like ''Raca'' (Ῥακά, an Aramaic insult meaning ''empty-headed'') puts one ''in danger of the council'' (τῷ συνεδρίῳ, the Sanhedrin). Calling someone ''Thou fool'' (Μωρέ, implying moral worthlessness) makes one ''in danger of hell fire'' (τὴν γέενναν τοῦ πυρός, Gehenna, the valley outside Jerusalem used for burning refuse, symbolizing eternal judgment). Jesus emphasizes that hatred in the heart is equivalent to murder (1 John 3:15).',
   'This verse profoundly deepens the understanding of the sixth commandment, revealing that God judges the heart. It teaches that anger, contemptuous speech, and hatred are spiritual equivalents to murder, demonstrating that sin originates internally and merits divine judgment, emphasizing the need for inner transformation.'),
  (23,
   'Therefore if thou bring thy gift to the altar, and there rememberest that thy brother hath ought against thee;',
   'Ἐὰν οὖν προσφέρῃς τὸ δῶρόν σου ἐπὶ τὸ θυσιαστήριον κἀκεῖ μνησθῇς ὅτι ὁ ἀδελφός σου ἔχει τι κατὰ σοῦ,',
   'Ean oun prospherēs to dōron sou epi to thysiastērion kakei mnēsthēs hoti ho adelphos sou echei ti kata sou,',
   'Jesus illustrates the gravity of unresolved interpersonal conflict, especially in light of the preceding teaching on anger. If one is about to offer a ''gift to the altar'' (τὸ δῶρόν σου ἐπὶ τὸ θυσιαστήριον), a sacred act of worship, but ''rememberest that thy brother hath ought against thee'' (ὁ ἀδελφός σου ἔχει τι κατὰ σοῦ), the spiritual priority shifts. This implies that reconciliation with others is a prerequisite for acceptable worship before God (1 Sam 15:22).',
   'This verse teaches that genuine worship of God is inextricably linked to reconciled relationships with fellow believers. It prioritizes interpersonal harmony over ritual, demonstrating that a pure heart and right standing with others are essential for acceptable communion with God.'),
  (24,
   'Leave there thy gift before the altar, and go thy way; first be reconciled to thy brother, and then come and offer thy gift.',
   'ἄφες ἐκεῖ τὸ δῶρόν σου ἔμπροσθεν τοῦ θυσιαστηρίου, καὶ ὕπαγε πρῶτον διαλλάγηθι τῷ ἀδελφῷ σου, καὶ τότε ἐλθὼν πρόσφερε τὸ δῶρόν σου.',
   'aphes ekei to dōron sou emprosthen tou thysiastēriou, kai hupage prōton diallagēthi tō adelphō sou, kai tote elthōn prosphere to dōron sou.',
   'The command is clear: ''Leave there thy gift before the altar'' (ἄφες ἐκεῖ τὸ δῶρόν σου ἔμπροσθεν τοῦ θυσιαστηρίου) and ''first be reconciled to thy brother'' (πρῶτον διαλλάγηθι τῷ ἀδελφῷ σου). Only ''then come and offer thy gift'' (τότε ἐλθὼν πρόσφερε τὸ δῶρόν σου). This radical instruction elevates horizontal relationships to a level of importance that precedes even vertical worship, emphasizing that true piety includes loving one''s neighbor as oneself (Matt 22:39).',
   'This verse powerfully teaches that reconciliation with others must precede and enable genuine worship of God. It underscores the profound theological truth that our relationship with God cannot be right if our relationships with fellow humans are broken, emphasizing the holistic nature of Christian discipleship.'),
  (25,
   'Agree with thine adversary quickly, whiles thou art in the way with him; lest at any time the adversary deliver thee to the judge, and the judge deliver thee to the officer, and thou be cast into prison.',
   'Ἴσθι εὐνοῶν τῷ ἀντιδίκῳ σου ταχύ, ἕως ὅτου εἶ ἐν τῇ ὁδῷ μετ’ αὐτοῦ, μή ποτέ σε παραδῷ ὁ ἀντίδικος τῷ κριτῇ, καὶ ὁ κριτὴς τῷ ὑπηρέτῃ, καὶ εἰς φυλακὴν βληθήσῃ·',
   'Isthi eunoon tō antidikō sou tachy, heōs hotou ei en tē hodō met'' autou, mē pote se paradō ho antidikos tō kritē, kai ho kritēs tō hypēretē, kai eis phylakēn blēthēsē;',
   'Jesus advises urgent reconciliation: ''Agree with thine adversary quickly'' (Ἴσθι εὐνοῶν τῷ ἀντιδίκῳ σου ταχύ) while there is still opportunity (''whiles thou art in the way with him''). This parable-like scenario describes the legal consequences of delaying reconciliation: being handed over to the ''judge'' (κριτῇ), then the ''officer'' (ὑπηρέτῃ), and finally ''cast into prison'' (εἰς φυλακὴν βληθήσῃ). While it has a literal legal application, it also serves as an analogy for spiritual judgment, urging prompt repentance and reconciliation (Luke 12:58-59).',
   'This verse, while having practical legal advice, carries a profound spiritual warning about the urgency of reconciliation. It teaches that delaying repentance and forgiveness can lead to severe consequences, both temporal and eternal, emphasizing the importance of proactively seeking peace and resolving conflict.'),
  (26,
   'Verily I say unto thee, Thou shalt by no means come out thence, till thou hast paid the uttermost farthing.',
   'ἀμὴν λέγω σοι, οὐ μὴ ἐξέλθῃς ἐκεῖθεν ἕως ἂν ἀποδῷς τὸν ἔσχατον κοδράντην.',
   'amēn legō soi, ou mē exelthēs ekeithen heōs an apodōs ton eschaton kodrantēn.',
   'The consequence of failing to reconcile is severe: ''Thou shalt by no means come out thence, till thou hast paid the uttermost farthing'' (οὐ μὴ ἐξέλθῃς ἐκεῖθεν ἕως ἂν ἀποδῷς τὸν ἔσχατον κοδράντην). A ''farthing'' (κοδράντην) was a very small Roman coin, emphasizing that even the smallest debt or offense must be settled. This reinforces the seriousness of unresolved conflict and the need for complete restitution, both literally and spiritually, before one can be truly free (Matt 18:34-35).',
   'This verse underscores the gravity of unresolved spiritual debt and the necessity of complete restitution or forgiveness. It teaches that divine justice demands full payment for sin, which for believers is met in Christ, but also implies that our failure to forgive others can hinder our own experience of God''s forgiveness.'),
  (27,
   'Ye have heard that it was said by them of old time, Thou shalt not commit adultery:',
   'Ἠκούσατε ὅτι ἐρρέθη, Οὐ μοιχεύσεις.',
   'Ēkousate hoti errhethē, Ou moicheuseis.',
   'Jesus introduces the second antithesis, addressing the seventh commandment: ''Thou shalt not commit adultery'' (Οὐ μοιχεύσεις) (Exod 20:14; Deut 5:18). Like the command against murder, the traditional interpretation focused primarily on the physical act of sexual infidelity. Jesus is about to reveal the deeper, internal dimension of this commandment, moving beyond outward behavior to the desires of the heart.',
   NULL),
  (28,
   'But I say unto you, That whosoever looketh on a woman to lust after her hath committed adultery with her already in his heart.',
   'Ἐγὼ δὲ λέγω ὑμῖν ὅτι πᾶς ὁ βλέπων γυναῖκα πρὸς τὸ ἐπιθυμῆσαι αὐτὴν ἤδη ἐμοίχευσεν αὐτὴν ἐν τῇ καρδίᾳ αὐτοῦ.',
   'Egō de legō humin hoti pas ho blepōn gynaika pros to epithymēsai autēn ēdē emoicheusen autēn en tē kardia autou.',
   'Jesus again elevates the standard: ''whosoever looketh on a woman to lust after her hath committed adultery with her already in his heart'' (πᾶς ὁ βλέπων γυναῖκα πρὸς τὸ ἐπιθυμῆσαι αὐτὴν ἤδη ἐμοίχευσεν αὐτὴν ἐν τῇ καρδίᾳ αὐτοῦ). This radical statement reveals that sin is not merely an external act but originates in the inner desires and intentions of the ''heart'' (καρδίᾳ). Lustful thoughts, even if not acted upon, are condemned as spiritual adultery, demonstrating God''s concern for inner purity (Prov 6:25; James 1:14-15).',
   'This verse profoundly redefines adultery, revealing that sin begins in the heart with lustful intent. It teaches that God''s moral law extends to our inner thoughts and desires, not just outward actions, emphasizing the need for radical internal purity and the transformative power of Christ over sinful inclinations.'),
  (29,
   'And if thy right eye offend thee, pluck it out, and cast it from thee: for it is profitable for thee that one of thy members should perish, and not that thy whole body should be cast into hell.',
   'Εἰ δὲ ὁ ὀφθαλμός σου ὁ δεξιὸς σκανδαλίζει σε, ἔξελε αὐτὸν καὶ βάλε ἀπὸ σοῦ· συμφέρει γάρ σοι ἵνα ἀπόληται ἓν τῶν μελῶν σου καὶ μὴ ὅλον σου τὸ σῶμα βληθῇ εἰς γέενναν.',
   'Ei de ho ophthalmos sou ho dexios skandalizei se, exele auton kai bale apo sou; sympherei gar soi hina apolētai hen tōn melōn sou kai mē holon sou to sōma blēthē eis geennan.',
   'Jesus uses hyperbole to emphasize the seriousness of sin and the radical measures required to avoid it. If ''thy right eye offend thee'' (ὁ ὀφθαλμός σου ὁ δεξιὸς σκανδαλίζει σε), meaning it causes you to stumble into sin, ''pluck it out, and cast it from thee'' (ἔξελε αὐτὸν καὶ βάλε ἀπὸ σοῦ). The point is not literal self-mutilation, but a decisive, ruthless separation from anything that leads to sin, because it is ''profitable for thee that one of thy members should perish, and not that thy whole body should be cast into hell'' (γέενναν) (Matt 18:8-9; Col 3:5).',
   'This verse, using hyperbole, teaches the radical necessity of severing ties with anything that causes spiritual stumbling. It underscores the extreme gravity of sin and the eternal consequences of unrepentance, urging believers to exercise ruthless self-discipline to preserve their souls from hell.'),
  (30,
   'And if thy right hand offend thee, cut it off, and cast it from thee: for it is profitable for thee that one of thy members should perish, and not that thy whole body should be cast into hell.',
   'Καὶ εἰ ἡ δεξιά σου χεὶρ σκανδαλίζει σε, ἔκκοψον αὐτὴν καὶ βάλε ἀπὸ σοῦ· συμφέρει γάρ σοι ἵνα ἀπόληται ἓν τῶν μελῶν σου καὶ μὴ ὅλον σου τὸ σῶμα εἰς γέενναν ἀπέλθῃ.',
   'Kai ei hē dexia sou cheir skandalizei se, ekkopson autēn kai bale apo sou; sympherei gar soi hina apolētai hen tōn melōn sou kai mē holon sou to sōma eis geennan apelthē.',
   'This verse reiterates the principle from verse 29, applying it to the ''right hand'' (ἡ δεξιά σου χεὶρ). The ''right'' eye and hand symbolize the most valuable and effective instruments of the body. The message is consistent: any part of one''s life, no matter how cherished or seemingly essential, that leads to sin must be decisively ''cut off'' (ἔκκοψον αὐτὴν) and cast away. The eternal consequence of ''hell'' (γέενναν) far outweighs any temporal loss or sacrifice (Mark 9:43-48).',
   'Echoing the previous verse, this passage reinforces the absolute priority of spiritual purity over physical comfort or worldly attachments. It teaches that radical self-denial and decisive action against sin are essential for salvation, emphasizing the eternal stakes involved in our moral choices.'),
  (31,
   'It hath been said, Whosoever shall put away his wife, let him give her a writing of divorcement:',
   'Ἐρρέθη δέ, Ὃς ἂν ἀπολύσῃ τὴν γυναῖκα αὐτοῦ, δότω αὐτῇ ἀποστάσιον.',
   'Errhethē de, Hos an apolysē tēn gynaika autou, dotō autē apostasion.',
   'Jesus introduces the third antithesis, concerning divorce. He quotes the Mosaic Law from Deuteronomy 24:1: ''Whosoever shall put away his wife, let him give her a writing of divorcement'' (Ὃς ἂν ἀπολύσῃ τὴν γυναῖκα αὐτοῦ, δότω αὐτῇ ἀποστάσιον). This law was intended to protect women from arbitrary dismissal and provide legal documentation, but it was often misused by men to divorce for trivial reasons, especially among the Pharisees (Matt 19:3).',
   NULL),
  (32,
   'But I say unto you, That whosoever shall put away his wife, saving for the cause of fornication, causeth her to commit adultery: and whosoever shall marry her that is divorced committeth adultery.',
   'Ἐγὼ δὲ λέγω ὑμῖν ὅτι πᾶς ὁ ἀπολύων τὴν γυναῖκα αὐτοῦ παρεκτὸς λόγου πορνείας ποιεῖ αὐτὴν μοιχευθῆναι, καὶ ὃς ἐὰν ἀπολελυμένην γαμήσῃ, μοιχᾶται.',
   'Egō de legō humin hoti pas ho apolyōn tēn gynaika autou parektos logou porneias poiei autēn moicheuthēnai, kai hos ean apolelymenēn gamēsē, moichatai.',
   'Jesus radically restricts the grounds for divorce: ''whosoever shall put away his wife, saving for the cause of fornication'' (πᾶς ὁ ἀπολύων τὴν γυναῖκα αὐτοῦ παρεκτὸς λόγου πορνείας) ''causeth her to commit adultery'' (ποιεῖ αὐτὴν μοιχευθῆναι). The Greek word ''πορνείας'' (porneias) refers to sexual immorality, encompassing a broader range than just adultery. Jesus declares that remarriage after an unbiblical divorce is also adultery. This teaching restores marriage to God''s original design for lifelong monogamous union, emphasizing its sacredness (Gen 2:24; Mal 2:16).',
   'This verse establishes Jesus'' strict teaching on divorce, limiting it to cases of ''fornication'' (sexual immorality) and declaring that unbiblical divorce and remarriage constitute adultery. It upholds the sanctity and permanence of marriage as a divine institution, emphasizing God''s original design for lifelong covenant fidelity.'),
  (33,
   'Again, ye have heard that it hath been said by them of old time, Thou shalt not forswear thyself, but shalt perform unto the Lord thine oaths:',
   'Πάλιν ἠκούσατε ὅτι ἐρρέθη τοῖς ἀρχαίοις, Οὐκ ἐπιορκήσεις, ἀποδώσεις δὲ τῷ Κυρίῳ τοὺς ὅρκους σου.',
   'Palin ēkousate hoti errhethē tois archaiois, Ouk epiorkēseis, apodōseis de tō Kyriō tous horkous sou.',
   'Jesus introduces the fourth antithesis, concerning oaths. He references the Old Testament teaching: ''Thou shalt not forswear thyself, but shalt perform unto the Lord thine oaths'' (Οὐκ ἐπιορκήσεις, ἀποδώσεις δὲ τῷ Κυρίῳ τοὺς ὅρκους σου) (Lev 19:12; Num 30:2; Deut 23:21). The Law condemned false swearing (perjury) and emphasized fulfilling vows made to God. However, Jewish tradition had developed complex casuistry, distinguishing between binding and non-binding oaths, often leading to deceit and evasion.',
   NULL),
  (34,
   'But I say unto you, Swear not at all; neither by heaven; for it is God’s throne:',
   'Ἐγὼ δὲ λέγω ὑμῖν μὴ ὀμόσαι ὅλως· μήτε ἐν τῷ οὐρανῷ, ὅτι θρόνος ἐστὶν τοῦ Θεοῦ·',
   'Egō de legō humin mē omosai holōs; mēte en tō ouranō, hoti thronos estin tou Theou;',
   'Jesus'' teaching is radical: ''Swear not at all'' (μὴ ὀμόσαι ὅλως). He forbids the practice of making oaths by various created things, such as ''heaven'' (τῷ οὐρανῷ), because it is ''God’s throne'' (θρόνος ἐστὶν τοῦ Θεοῦ). The underlying principle is that all creation belongs to God, and therefore, any oath, even if not directly by God''s name, implicitly invokes His authority. This teaching aims to cultivate absolute truthfulness in all speech, eliminating the need for oaths to validate one''s word (James 5:12).',
   'This verse teaches a radical standard of truthfulness, forbidding the casual use of oaths. It implies that all speech should be so trustworthy that oaths become unnecessary, reflecting God''s absolute truthfulness and demanding integrity in every word spoken by His children.'),
  (35,
   'Nor by the earth; for it is his footstool: neither by Jerusalem; for it is the city of the great King.',
   'μήτε ἐν τῇ γῇ, ὅτι ὑποπόδιόν ἐστιν τῶν ποδῶν αὐτοῦ· μήτε εἰς Ἱεροσόλυμα, ὅτι πόλις ἐστὶν τοῦ μεγάλου Βασιλέως.',
   'mēte en tē gē, hoti hypopodion estin tōn podōn autou; mēte eis Hierosolyma, hoti polis estin tou megalou Basileōs.',
   'Jesus continues to list examples of forbidden oaths, emphasizing God''s sovereignty over all creation. Swearing by ''the earth'' (τῇ γῇ) is forbidden because it is ''his footstool'' (ὑποπόδιόν ἐστιν τῶν ποδῶν αὐτοῦ, echoing Isa 66:1). Swearing by ''Jerusalem'' (Ἱεροσόλυμα) is forbidden because it is ''the city of the great King'' (πόλις ἐστὶν τοῦ μεγάλου Βασιλέως, Ps 48:2). These examples underscore that everything is under God''s dominion, making any oath by them ultimately an oath by God Himself.',
   'This verse reinforces God''s absolute sovereignty over all creation, from the earth to Jerusalem. It teaches that because everything belongs to God, any oath made by created things implicitly invokes His authority, thus demanding reverence and truthfulness in all speech, acknowledging His omnipresence.'),
  (36,
   'Neither shalt thou swear by thy head, because thou canst not make one hair white or black.',
   'μήτε ἐν τῇ κεφαλῇ σου ὀμόσῃς, ὅτι οὐ δύνασαι μίαν τρίχα λευκὴν ποιῆσαι ἢ μέλαιναν.',
   'mēte en tē kephalē sou omosēs, hoti ou dynasai mian trichan leukēn poiēsai ē melainan.',
   'Finally, Jesus forbids swearing ''by thy head'' (τῇ κεφαλῇ σου), giving a practical reason: ''because thou canst not make one hair white or black'' (οὐ δύνασαι μίαν τρίχα λευκὴν ποιῆσαι ἢ μέλαιναν). This highlights human powerlessness and lack of ultimate control, even over one''s own body. Since humans cannot guarantee even the smallest detail of their own existence, they have no basis for swearing by themselves. This further reinforces the call for simple, unadorned truthfulness (Luke 12:6-7).',
   'This verse emphasizes human dependence on God and our lack of ultimate control, even over our own bodies. It teaches that since we cannot control even a single hair, we have no basis for swearing by ourselves, reinforcing the call for absolute honesty and reliance on God''s sovereignty.'),
  (37,
   'But let your communication be, Yea, yea; Nay, nay: for whatsoever is more than these cometh of evil.',
   'ἔστω δὲ ὁ λόγος ὑμῶν ναὶ ναί, οὒ οὔ· τὸ δὲ περισσὸν τούτων ἐκ τοῦ πονηροῦ ἐστιν.',
   'estō de ho logos humōn nai nai, ou ou; to de perisson toutōn ek tou ponērou estin.',
   'Instead of oaths, Jesus prescribes simple, straightforward communication: ''Let your communication be, Yea, yea; Nay, nay'' (ἔστω δὲ ὁ λόγος ὑμῶν ναὶ ναί, οὒ οὔ). This means one''s word should be so reliable that a simple ''yes'' or ''no'' is sufficient. Anything ''more than these cometh of evil'' (τὸ δὲ περισσὸν τούτων ἐκ τοῦ πονηροῦ ἐστιν), implying that the need for oaths arises from a lack of trust, which is ultimately rooted in the evil one or human deceit (James 5:12).',
   'This verse establishes a radical standard for Christian speech: absolute truthfulness and simplicity. It teaches that believers'' words should be so trustworthy that oaths are unnecessary, and anything beyond a simple ''yes'' or ''no'' indicates a lack of integrity, ultimately stemming from evil or human fallenness.'),
  (38,
   'Ye have heard that it hath been said, An eye for an eye, and a tooth for a tooth:',
   'Ἠκούσατε ὅτι ἐρρέθη, Ὀφθαλμὸν ἀντὶ ὀφθαλμοῦ καὶ ὀδόντα ἀντὶ ὀδόντος.',
   'Ēkousate hoti errhethē, Ophthalmon anti ophthalmou kai odonta anti odontos.',
   'Jesus introduces the fifth antithesis, addressing the principle of ''lex talionis'' or ''An eye for an eye, and a tooth for a tooth'' (Ὀφθαλμὸν ἀντὶ ὀφθαλμοῦ καὶ ὀδόντα ἀντὶ ὀδόντος) (Exod 21:24; Lev 24:20; Deut 19:21). This Old Testament law was given to limit vengeance and ensure justice by prescribing proportional retribution, preventing excessive retaliation. However, it was often interpreted as a justification for personal revenge, which Jesus now challenges.',
   NULL),
  (39,
   'But I say unto you, That ye resist not evil: but whosoever shall smite thee on thy right cheek, turn to him the other also.',
   'Ἐγὼ δὲ λέγω ὑμῖν μὴ ἀντιστῆναι τῷ πονηρῷ· ἀλλ’ ὅστις σε ῥαπίσει ἐπὶ τὴν δεξιὰν σιαγόνα, στρέψον αὐτῷ καὶ τὴν ἄλλην.',
   'Egō de legō humin mē antistēnai tō ponērō; all'' hostis se rapisei epi tēn dexian siagona, strepson autō kai tēn allēn.',
   'Jesus'' command is revolutionary: ''ye resist not evil'' (μὴ ἀντιστῆναι τῷ πονηρῷ). This is not a call to passive acceptance of all evil, but a rejection of personal retaliation. He illustrates with ''whosoever shall smite thee on thy right cheek, turn to him the other also'' (ὅστις σε ῥαπίσει ἐπὶ τὴν δεξιὰν σιαγόνα, στρέψον αὐτῷ καὶ τὴν ἄλλην). A backhand slap on the right cheek was a grave insult. Jesus calls for a response that disarms the aggressor, breaks the cycle of violence, and demonstrates radical love and humility (Luke 6:29).',
   'This verse introduces a radical ethic of non-retaliation, challenging the principle of ''an eye for an eye.'' It teaches believers to respond to personal insults and aggression with humility and love, rather than vengeance, thereby breaking cycles of violence and demonstrating a Christ-like commitment to peace and forgiveness.'),
  (40,
   'And if any man will sue thee at the law, and take away thy coat, let him have thy cloak also.',
   'Καὶ τῷ θέλοντί σοι κριθῆναι καὶ τὸν χιτῶνά σου λαβεῖν, ἄφες αὐτῷ καὶ τὸ ἱμάτιον.',
   'Kai tō thelonti soi krithēnai kai ton chitōna sou labein, aphes autō kai to himation.',
   'Jesus extends the principle of non-retaliation to legal disputes. If someone ''will sue thee at the law, and take away thy coat'' (τῷ θέλοντί σοι κριθῆναι καὶ τὸν χιτῶνά σου λαβεῖν, the inner garment), the disciple should ''let him have thy cloak also'' (ἄφες αὐτῷ καὶ τὸ ἱμάτιον, the outer, more valuable garment, often used as collateral or a blanket). This goes beyond merely not resisting; it advocates for generous, self-sacrificial love that willingly gives more than is demanded, demonstrating a kingdom ethic that transcends legal rights (1 Cor 6:7).',
   'This verse extends the principle of non-retaliation to legal and material disputes, advocating for radical generosity and self-sacrifice. It teaches believers to willingly surrender their rights and possessions, even beyond what is demanded, demonstrating a counter-cultural love that prioritizes reconciliation and God''s glory over personal gain.'),
  (41,
   'And whosoever shall compel thee to go a mile, go with him twain.',
   'Καὶ ὅστις σε ἀγγαρεύσει μίλιον ἕν, ὕπαγε μετ’ αὐτοῦ δύο.',
   'Kai hostis se angareusei milion hen, hupage met'' autou duo.',
   'This example refers to the Roman practice of ''impressment'' (ἀγγαρεύσει), where an authority could compel a person to carry a burden or perform a service for a certain distance, typically one mile. Jesus commands, ''whosoever shall compel thee to go a mile, go with him twain'' (ὕπαγε μετ’ αὐτοῦ δύο). This proactive generosity and willingness to go beyond the required duty exemplifies a spirit of humble service and love, transforming a forced obligation into a voluntary act of kindness (Rom 12:20-21).',
   'This verse teaches a radical ethic of voluntary service and generosity, even towards those who impose burdens. It calls believers to ''go the extra mile,'' transforming forced obligations into acts of selfless love, thereby demonstrating a kingdom principle that transcends mere duty and seeks to bless others.'),
  (42,
   'Give to him that asketh thee, and from him that would borrow of thee turn not thou away.',
   'Δὸς τῷ αἰτοῦντί σε, καὶ τὸν θέλοντα ἀπὸ σοῦ δανίσασθαι μὴ ἀποστραφῇς.',
   'Dos tō aitounti se, kai ton thelonta apo sou danisasthai mē apostraphēs.',
   'Jesus gives a direct command regarding generosity: ''Give to him that asketh thee, and from him that would borrow of thee turn not thou away'' (Δὸς τῷ αἰτοῦντί σε, καὶ τὸν θέλοντα ἀπὸ σοῦ δανίσασθαι μὴ ἀποστραφῇς). This instruction encourages open-handed generosity and a willingness to help those in need, without expecting repayment or being selective in one''s giving. It reflects God''s own generosity towards humanity and calls for a compassionate heart (Deut 15:7-8; Luke 6:30).',
   'This verse emphasizes radical generosity and compassion towards those in need. It teaches believers to give freely and lend willingly, reflecting God''s own benevolent character and fostering a community where mutual support and love are prioritized over self-interest or fear of loss.'),
  (43,
   'Ye have heard that it hath been said, Thou shalt love thy neighbour, and hate thine enemy.',
   'Ἠκούσατε ὅτι ἐρρέθη, Ἀγαπήσεις τὸν πλησίον σου καὶ μισήσεις τὸν ἐχθρόν σου.',
   'Ēkousate hoti errhethē, Agapēseis ton plēsion sou kai misēseis ton echthron sou.',
   'Jesus introduces the sixth and final antithesis, concerning love. He quotes the command to ''love thy neighbour'' (Ἀγαπήσεις τὸν πλησίον σου) from Leviticus 19:18. However, the second part, ''and hate thine enemy'' (καὶ μισήσεις τὸν ἐχθρόν σου), is not found in the Old Testament. It represents a common rabbinic interpretation or popular sentiment of the day, which limited the scope of love and justified animosity towards enemies, a view Jesus is about to overturn.',
   NULL),
  (44,
   'But I say unto you, Love your enemies, bless them that curse you, do good to them that hate you, and pray for them which despitefully use you, and persecute you;',
   'Ἐγὼ δὲ λέγω ὑμῖν, ἀγαπᾶτε τοὺς ἐχθροὺς ὑμῶν, εὐλογεῖτε τοὺς καταρωμένους ὑμᾶς, καλῶς ποιεῖτε τοὺς μισοῦντας ὑμᾶς, καὶ προσεύχεσθε ὑπὲρ τῶν ἐπηρεαζόντων ὑμᾶς καὶ διωκόντων ὑμᾶς·',
   'Egō de legō humin, agapate tous echthrous humōn, eulogeite tous katarōmenous humas, kalōs poieite tous misountas humas, kai proseuchesthe huper tōn epēreazontōn humas kai diōkontōn humas:',
   'Jesus'' command is the pinnacle of kingdom ethics: ''Love your enemies'' (ἀγαπᾶτε τοὺς ἐχθροὺς ὑμῶν). This ''agape'' love is not an emotion but a deliberate act of the will, seeking the good of others regardless of their actions. He specifies how: ''bless them that curse you, do good to them that hate you, and pray for them which despitefully use you, and persecute you'' (εὐλογεῖτε τοὺς καταρωμένους ὑμᾶς, καλῶς ποιεῖτε τοὺς μισοῦντας ὑμᾶς, καὶ προσεύχεσθε ὑπὲρ τῶν ἐπηρεαζόντων ὑμᾶς καὶ διωκόντων ὑμᾶς). This radical love mirrors God''s own character (Rom 12:14; Luke 6:27-28).',
   'This verse presents the most radical and distinctive command of Christian ethics: to love one''s enemies. It teaches that ''agape'' love extends even to those who persecute us, manifesting through blessing, doing good, and prayer. This divine standard reflects God''s own character and is foundational to Christian discipleship, demonstrating the transformative power of the gospel.'),
  (45,
   'That ye may be the children of your Father which is in heaven: for he maketh his sun to rise on the evil and on the good, and sendeth rain on the just and on the unjust.',
   'ὅπως γένησθε υἱοὶ τοῦ Πατρὸς ὑμῶν τοῦ ἐν οὐρανοῖς, ὅτι τὸν ἥλιον αὐτοῦ ἀνατέλλει ἐπὶ πονηροὺς καὶ ἀγαθοὺς καὶ βρέχει ἐπὶ δικαίους καὶ ἀδίκους.',
   'hopōs genēsthe huioi tou Patros humōn tou en ouranois, hoti ton hēlion autou anatellei epi ponērous kai agathous kai brechei epi dikaious kai adikous.',
   'The motivation for loving enemies is to ''be the children of your Father which is in heaven'' (γένησθε υἱοὶ τοῦ Πατρὸς ὑμῶν τοῦ ἐν οὐρανοῖς). This means reflecting God''s character. Jesus illustrates God''s impartial benevolence: ''he maketh his sun to rise on the evil and on the good, and sendeth rain on the just and on the unjust'' (τὸν ἥλιον αὐτοῦ ἀνατέλλει ἐπὶ πονηροὺς καὶ ἀγαθοὺς καὶ βρέχει ἐπὶ δικαίους καὶ ἀδίκους). God''s common grace extends to all humanity, regardless of their moral standing. Disciples are called to imitate this divine, unconditional love (Acts 14:17).',
   'This verse reveals the theological basis for loving enemies: to emulate God''s character. It teaches that God''s common grace extends impartially to all humanity, both righteous and unrighteous. Believers are called to reflect this divine, unconditional love, thereby demonstrating their true sonship and likeness to their Heavenly Father.'),
  (46,
   'For if ye love them which love you, what reward have ye? do not even the publicans the same?',
   'Ἐὰν γὰρ ἀγαπήσητε τοὺς ἀγαπῶντας ὑμᾶς, τίνα μισθὸν ἔχετε; οὐχὶ καὶ οἱ τελῶναι τὸ αὐτὸ ποιοῦσιν;',
   'Ean gar agapēsēte tous agapōntas humas, tina misthon echete? ouchi kai hoi telōnai to auto poiousin?',
   'Jesus challenges the conventional understanding of love by asking, ''For if ye love them which love you, what reward have ye?'' (Ἐὰν γὰρ ἀγαπήσητε τοὺς ἀγαπῶντας ὑμᾶς, τίνα μισθὸν ἔχετε;). He points out that even ''the publicans'' (οἱ τελῶναι)—tax collectors, who were despised for their collaboration with Rome and often extortionate practices—''do the same'' (τὸ αὐτὸ ποιοῦσιν). This highlights that merely reciprocating love is not a distinguishing mark of kingdom citizens; true righteousness demands a higher, supernatural love (Luke 6:32).',
   'This verse challenges believers to transcend conventional human love, which is often conditional and reciprocal. It teaches that merely loving those who love us offers no unique ''reward'' in God''s kingdom, as even the unrighteous do the same, thus calling for a higher, transformative love that reflects divine grace.'),
  (47,
   'And if ye salute your brethren only, what do ye more than others? do not even the publicans so?',
   'Καὶ ἐὰν ἀσπάσησθε τοὺς ἀδελφοὺς ὑμῶν μόνον, τί περισσὸν ποιεῖτε; οὐχὶ καὶ οἱ ἐθνικοὶ τὸ αὐτὸ ποιοῦσιν;',
   'Kai ean aspasēsthe tous adelphous humōn monon, ti perisson poieite? ouchi kai hoi ethnikoi to auto poiousin?',
   'Extending the argument, Jesus asks, ''And if ye salute your brethren only, what do ye more than others?'' (Ἐὰν ἀσπάσησθε τοὺς ἀδελφοὺς ὑμῶν μόνον, τί περισσὸν ποιεῖτε;). ''Saluting'' (ἀσπάσησθε) implies a greeting of peace and fellowship. He notes that ''even the publicans'' (οἱ ἐθνικοὶ, often translated as ''Gentiles'' or ''heathens'' in other contexts, here referring to those outside the covenant, akin to publicans in their moral standing) ''do so'' (τὸ αὐτὸ ποιοῦσιν). This reinforces the call for a love that goes beyond tribal or familial boundaries, reflecting God''s universal love (Luke 6:33).',
   'This verse reinforces the call for a love that transcends social and familial boundaries. It teaches that merely extending kindness to one''s own group is not a distinguishing mark of Christian discipleship, as even unbelievers do the same, thus urging believers to demonstrate a more expansive, God-like love.'),
  (48,
   'Be ye therefore perfect, even as your Father which is in heaven is perfect.',
   'Ἔσεσθε οὖν ὑμεῖς τέλειοι, ὡς ὁ Πατὴρ ὑμῶν ὁ ἐν τοῖς οὐρανοῖς τέλειός ἐστιν.',
   'Esesthe oun humeis teleioi, hōs ho Patēr humōn ho en tois ouranois teleios estin.',
   'This verse serves as the climax of the Sermon on the Mount''s ethical demands: ''Be ye therefore perfect, even as your Father which is in heaven is perfect'' (Ἔσεσθε οὖν ὑμεῖς τέλειοι, ὡς ὁ Πατὴρ ὑμῶν ὁ ἐν τοῖς οὐρανοῖς τέλειός ἐστιν). ''Perfect'' (τέλειοι) here means complete, mature, or whole, especially in love and moral character, rather than absolute sinlessness. It is a call to imitate God''s comprehensive, impartial love and righteousness, particularly as demonstrated in loving enemies. This is a lifelong pursuit, empowered by the Holy Spirit (Col 1:28; 1 Pet 1:15-16).',
   'This culminating verse presents the ultimate ethical standard for kingdom citizens: to be ''perfect'' (complete or mature) in love and righteousness, mirroring God''s own character. It teaches that Christian discipleship is a lifelong pursuit of holiness, empowered by God, to reflect His comprehensive and impartial love to the world, demonstrating the transformative power of the gospel.')
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Matthew' AND c.chapter_number = 5;

-- Step 3: Word Studies for key verses

-- Verse 3
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, ws.original_word, ws.transliteration, ws.strongs_number, ws.meaning, ws.word_order
FROM verses v
JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  ('πτωχοὶ', 'ptōchoi', 'G4434', 'From ''πτώσσω (ptōssō)'', meaning ''to cower, crouch''. It describes one who is utterly destitute, a beggar, dependent on others for survival. Spiritually, ''poor in spirit'' refers to a profound humility, recognizing one''s complete spiritual bankruptcy and absolute dependence on God''s grace for salvation and righteousness.', 1),
  ('πνεύματι', 'pneumati', 'G4151', 'Refers to the spirit, breath, or wind. In this context, ''in spirit'' (dative case) specifies the realm or aspect of poverty. It denotes an internal disposition, indicating a humble and contrite heart that acknowledges its spiritual need and emptiness before God, rather than a material lack.', 2),
  ('βασιλεία', 'basileia', 'G932', 'Meaning ''kingdom, reign, royal power, dominion''. In the phrase ''kingdom of heaven'' (or ''kingdom of God''), it signifies God''s sovereign rule and reign, both present in the hearts of believers and future in its full eschatological manifestation. It is a central theme of Jesus'' teaching, representing God''s redemptive activity and the sphere of His authority.', 3)
) AS ws(original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Matthew' AND c.chapter_number = 5 AND v.verse_number = 3;

-- Verse 6
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, ws.original_word, ws.transliteration, ws.strongs_number, ws.meaning, ws.word_order
FROM verses v
JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  ('πεινῶντες', 'peinōntes', 'G3983', 'Meaning ''to hunger, to be hungry''. Here, used metaphorically, it describes an intense, deep-seated spiritual craving or longing. It signifies a profound dissatisfaction with one''s own spiritual state and a fervent, active pursuit of something essential for life, akin to physical hunger for food.', 1),
  ('δικαιοσύνην', 'dikaiosynēn', 'G1343', 'From ''δίκαιος (dikaios)'', meaning ''just, righteous''. It refers to conformity to God''s standard, both in character and action. It encompasses ethical uprightness, justice, and the state of being right with God. In Matthew, Jesus redefines it as an internal disposition exceeding mere external legalism, essential for kingdom entry.', 2),
  ('χορτασθήσονται', 'chortasthēsontai', 'G5526', 'Meaning ''to feed, to satisfy with food, to be filled''. Originally used for feeding animals, it came to mean full satisfaction. In this spiritual context, it promises complete fulfillment and contentment for those who hunger for righteousness, implying that God will abundantly provide for their spiritual needs and longings.', 3)
) AS ws(original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Matthew' AND c.chapter_number = 5 AND v.verse_number = 6;

-- Verse 8
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, ws.original_word, ws.transliteration, ws.strongs_number, ws.meaning, ws.word_order
FROM verses v
JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  ('καθαροὶ', 'katharoi', 'G2513', 'Meaning ''clean, pure, unmixed, undefiled''. In a moral and spiritual sense, it refers to inner purity, sincerity, and freedom from hypocrisy or duplicity. It denotes an undivided heart, wholly devoted to God, with motives that are transparent and uncorrupted by sin.', 1),
  ('καρδίᾳ', 'kardia', 'G2588', 'Refers to the heart, the center of one''s being, encompassing intellect, emotion, and will. ''Pure in heart'' emphasizes that true purity is not merely external but originates from the innermost core of a person, where thoughts, intentions, and desires reside, reflecting a genuine spiritual state.', 2),
  ('ὄψονται', 'opsontai', 'G3700', 'From ''ὁράω (horaō)'', meaning ''to see, perceive, behold''. This promise signifies an intimate, unhindered fellowship and direct knowledge of God. It implies both a spiritual discernment of God''s presence in this life and an ultimate, unveiled vision of His glory in the eschatological future, a profound blessing.', 3)
) AS ws(original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Matthew' AND c.chapter_number = 5 AND v.verse_number = 8;

-- Verse 17
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, ws.original_word, ws.transliteration, ws.strongs_number, ws.meaning, ws.word_order
FROM verses v
JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  ('καταλῦσαι', 'katalysai', 'G2647', 'Meaning ''to loosen down, to pull down, to destroy, to abolish''. In this context, it refers to annulling or rendering the Law and the Prophets invalid or obsolete. Jesus emphatically denies this intention, asserting that his mission is not to dismantle the Old Testament revelation but to uphold its authority.', 1),
  ('πληρῶσαι', 'plērōsai', 'G4137', 'Meaning ''to fill, to complete, to fulfill''. In relation to the Law and the Prophets, Jesus'' fulfillment means several things: He perfectly obeyed them, He revealed their full spiritual meaning, He brought their prophecies to completion, and He brought them to their intended purpose in His person and work, establishing the New Covenant.', 2)
) AS ws(original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Matthew' AND c.chapter_number = 5 AND v.verse_number = 17;

-- Verse 20
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, ws.original_word, ws.transliteration, ws.strongs_number, ws.meaning, ws.word_order
FROM verses v
JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  ('περισσεύσῃ', 'perisseusē', 'G4052', 'Meaning ''to abound, to be over and above, to exceed''. Here, it emphasizes that the righteousness required for kingdom entry must not merely equal but significantly surpass the external, legalistic righteousness of the scribes and Pharisees. It points to a qualitative difference, an internal transformation rather than mere outward conformity.', 1),
  ('δικαιοσύνη', 'dikaiosynē', 'G1343', 'From ''δίκαιος (dikaios)'', meaning ''just, righteous''. It refers to conformity to God''s standard, both in character and action. It encompasses ethical uprightness, justice, and the state of being right with God. In Matthew, Jesus redefines it as an internal disposition exceeding mere external legalism, essential for kingdom entry.', 2),
  ('εἰσέλθητε', 'eiselthēte', 'G1525', 'Meaning ''to go in, to enter''. In the context of the ''kingdom of heaven,'' it refers to gaining access to or becoming a participant in God''s sovereign rule and redemptive community. Jesus'' statement makes it clear that a specific, higher standard of righteousness is a prerequisite for this entry.', 3)
) AS ws(original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Matthew' AND c.chapter_number = 5 AND v.verse_number = 20;

-- Verse 22
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, ws.original_word, ws.transliteration, ws.strongs_number, ws.meaning, ws.word_order
FROM verses v
JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  ('ὀργιζόμενος', 'orgizomenos', 'G3710', 'Meaning ''to be angry, to be provoked''. Jesus expands the prohibition against murder to include the internal state of unjustified anger towards a brother. This reveals that sin originates in the heart and that God judges not only actions but also the underlying emotions and intentions.', 1),
  ('Ῥακά', 'Rhaka', 'G4469', 'An Aramaic term of contempt, meaning ''empty one'' or ''worthless one''. It was a severe insult implying a person''s utter lack of intelligence or moral substance. Jesus equates such contemptuous speech with a serious offense, subject to the ''council'' (Sanhedrin), highlighting the gravity of demeaning others.', 2),
  ('Μωρέ', 'Mōre', 'G3474', 'A Greek term meaning ''fool''. In this context, it implies moral and spiritual worthlessness, suggesting a person is beyond redemption or utterly godless. Jesus declares that such a judgment on another''s character puts one in danger of ''hell fire'' (Gehenna), emphasizing the sacredness of human dignity and God''s ultimate judgment.', 3),
  ('γέενναν', 'geennan', 'G1067', 'From the Hebrew ''Ge Hinnom'' (Valley of Hinnom), a valley outside Jerusalem where refuse was burned and, historically, child sacrifices were offered. It became a metaphor for eternal punishment and destruction, symbolizing the ultimate judgment of God. Jesus uses it to denote the most severe consequence of sin.', 4)
) AS ws(original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Matthew' AND c.chapter_number = 5 AND v.verse_number = 22;

-- Verse 48
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, ws.original_word, ws.transliteration, ws.strongs_number, ws.meaning, ws.word_order
FROM verses v
JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  ('Ἔσεσθε', 'Esesthe', 'G1510', 'From ''εἰμί (eimi)'', meaning ''to be''. Here, in the imperative form, it is a command: ''Be'' or ''You shall be''. It signifies an active call to become or strive towards a particular state, emphasizing the ongoing process of transformation and growth in Christian character, rather than a static declaration.', 1),
  ('τέλειοι', 'teleioi', 'G5046', 'Meaning ''complete, perfect, mature, fully developed''. In this context, it does not imply absolute sinlessness, but rather a completeness or wholeness in moral character, particularly in the realm of love and righteousness, mirroring God''s comprehensive and impartial love. It is a goal of spiritual maturity and ethical consistency.', 2),
  ('Πατὴρ', 'Patēr', 'G3962', 'Meaning ''father''. Here, it refers to God as the Heavenly Father, emphasizing His divine parenthood and the intimate relationship believers have with Him. The call to be perfect ''as your Father'' highlights the imitative nature of Christian ethics, where God''s character serves as the ultimate standard and example for His children.', 3)
) AS ws(original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Matthew' AND c.chapter_number = 5 AND v.verse_number = 48;

